+  it.effect('uses a FAQ draft with no published object as a valid source', () =>
+    Effect.gen(function* () {
+      const draftPage = FaqPage.make({
+        ...defaultFaqPage,
+        title: { en: 'Draft FAQ', fr: 'FAQ brouillon' },
